outputs.main.sas:
* Program: t1_1_sdtm_suppdm_gen_016.sas
* Purpose: Create SDTM SUPPDM domain dataset
* Input: Raw supplemental DM data (suppdm_raw)
* Output: sdtm.suppdm (XPORT format)

libname raw "&rawpath";
libname sdtm "&sdtmpath";

* Read raw supplemental DM data;
data suppdm_raw;
  set raw.suppdm_raw;
run;

* Sort by subject and sequence;
proc sort data=suppdm_raw;
  by usubjid suppdmseq;
run;

* Create SUPPDM dataset with SDTM mapping;
data sdtm.suppdm (label="Supplemental Qualifiers for DM");
  attrib
    STUDYID    length=$40  label="Study Identifier"
    RDOMAIN    length=$2   label="Related Domain Abbreviation"
    USUBJID    length=$40  label="Unique Subject Identifier"
    IDVAR      length=$8   label="Identifying Variable"
    IDVARVAL   length=$200 label="Identifying Variable Value"
    QNAM       length=$8   label="Qualifier Variable Name"
    QLABEL     length=$40  label="Qualifier Variable Label"
    QVAL       length=$200 label="Qualifier Variable Value"
    QORIG      length=$1   label="Qualifier Origin"
    QEVAL      length=$40  label="Qualifier Evaluator"
    SUPPDMSEQ  length=8    label="Sequence Number"
  ;

  set suppdm_raw;
  by usubjid suppdmseq;

  * Derive USUBJID if not present;
  if missing(usubjid) then usubjid = catx("-", studyid, siteid, subjid);

  * Derive sequence number per subject;
  if first.usubjid then seq_counter = 0;
  seq_counter + 1;
  suppdmseq = seq_counter;

  * Map RDOMAIN to DM;
  rdomain = "DM";

  * Map IDVAR and IDVARVAL based on QNAM;
  select (qnam);
    when ("AGE") do;
      idvar = "AGE";
      idvarval = put(age, best.);
    end;
    when ("SEX") do;
      idvar = "SEX";
      idvarval = sex;
    end;
    when ("RACE") do;
      idvar = "RACE";
      idvarval = race;
    end;
    when ("ETHNIC") do;
      idvar = "ETHNIC";
      idvarval = ethnic;
    end;
    when ("ARMCD") do;
      idvar = "ARMCD";
      idvarval = armcd;
    end;
    when ("ARM") do;
      idvar = "ARM";
      idvarval = arm;
    end;
    when ("ACTARMCD") do;
      idvar = "ACTARMCD";
      idvarval = actarmcd;
    end;
    when ("ACTARM") do;
      idvar = "ACTARM";
      idvarval = actarm;
    end;
    when ("COUNTRY") do;
      idvar = "COUNTRY";
      idvarval = country;
    end;
    when ("SITEID") do;
      idvar = "SITEID";
      idvarval = siteid;
    end;
    when ("INVID") do;
      idvar = "INVID";
      idvarval = invid;
    end;
    when ("INVNAM") do;
      idvar = "INVNAM";
      idvarval = invnam;
    end;
    when ("BRTHDTC") do;
      idvar = "BRTHDTC";
      idvarval = brthdtc;
    end;
    when ("AGEU") do;
      idvar = "AGEU";
      idvarval = ageu;
    end;
    when ("SEXU") do;
      idvar = "SEXU";
      idvarval = sexu;
    end;
    when ("RACEU") do;
      idvar = "RACEU";
      idvarval = raceu;
    end;
    when ("ETHNICU") do;
      idvar = "ETHNICU";
      idvarval = ethnicu;
    end;
    when ("DMDTC") do;
      idvar = "DMDTC";
      idvarval = dmdtc;
    end;
    when ("DMDY") do;
      idvar = "DMDY";
      idvarval = put(dmdy, best.);
    end;
    otherwise do;
      idvar = "DMSEQ";
      idvarval = put(dmseq, best.);
    end;
  end;

  * Set QLABEL based on QNAM;
  select (qnam);
    when ("AGE")     qlabel = "Age";
    when ("SEX")     qlabel = "Sex";
    when ("RACE")    qlabel = "Race";
    when ("ETHNIC")  qlabel = "Ethnicity";
    when ("ARMCD")   qlabel = "Planned Arm Code";
    when ("ARM")     qlabel = "Planned Arm";
    when ("ACTARMCD") qlabel = "Actual Arm Code";
    when ("ACTARM")  qlabel = "Actual Arm";
    when ("COUNTRY") qlabel = "Country";
    when ("SITEID")  qlabel = "Site Identifier";
    when ("INVID")   qlabel = "Investigator Identifier";
    when ("INVNAM")  qlabel = "Investigator Name";
    when ("BRTHDTC") qlabel = "Date/Time of Birth";
    when ("AGEU")    qlabel = "Age Units";
    when ("SEXU")    qlabel = "Sex Units";
    when ("RACEU")   qlabel = "Race Units";
    when ("ETHNICU") qlabel = "Ethnicity Units";
    when ("DMDTC")   qlabel = "Date/Time of Demographics Collection";
    when ("DMDY")    qlabel = "Study Day of Demographics Collection";
    otherwise        qlabel = qnam;
  end;

  * Set QORIG to CRF as default;
  if missing(qorig) then qorig = "C";

  * Drop temporary variables;
  drop seq_counter;
run;

* Sort final dataset;
proc sort data=sdtm.suppdm;
  by studyid usubjid rdomain idvar idvarval qnam;
run;

* Create XPORT transport file;
libname xport xport "&outpath/suppdm.xpt";
data xport.suppdm;
  set sdtm.suppdm;
run;
libname xport clear;

* Verify record count;
proc sql;
  select count(*) as rec_count from sdtm.suppdm;
quit;
